import React, { useEffect, useState } from "react";
import api from "../api";
import FoodCard from "../components/FoodCard";

export default function FoodMenu() {
  const [foods, setFoods] = useState([]);


useEffect(() => {
  const fetchFoods = async () => {
    const res = await api.get("/foods");
    setFoods(res.data);
  };
  fetchFoods();
}, []);

  const placeOrder = async (foodId) => {

    await apiRequest("/orders", "POST", { items: [{ food: foodId, quantity: 1 }] }, token);
    alert("Order placed!");
  };

  return (
    <div className="row">
      {foods.map((food) => (
        <FoodCard key={food._id} food={food} onOrder={placeOrder} />
      ))}
    </div>
  );
}
